#!/usr/bin/env bash
set -euo pipefail

# P-04 submission check script.
#
# Usage:
#   ./run_submission_checks.sh --video   # <= ~5 min: compile + quick run + summarize saved reports
#   ./run_submission_checks.sh --full    # long: rerun official 7-seed report.json
#
# The video mode is intended for screen recording. It creates timestamped logs
# while avoiding a 10+ minute full rerun. The official 7-seed result is read
# from report.json, which is generated by --full / the official command.

MODE="${1:---video}"
if [[ "$MODE" != "--video" && "$MODE" != "--full" ]]; then
  echo "Usage: $0 [--video|--full]"
  exit 2
fi

ROOT="$(cd "$(dirname "$0")" && pwd)"
cd "$ROOT"
mkdir -p logs
STAMP="$(date +%Y%m%d_%H%M%S)"
LOG="logs/submission_${MODE#--}_${STAMP}.log"

# Prefer a local venv if present. If this cleaned submission folder has no
# local venv, fall back to the archived validation venv used during prep.
PY="python3"
if [[ -x ".venv/bin/python" ]]; then
  PY=".venv/bin/python"
elif [[ -x "/Users/adityakumarrai/.openclaw/workspace/p04_submission_archive_20260516_082924/final_structure_cleanup/.venv/bin/python" ]]; then
  PY="/Users/adityakumarrai/.openclaw/workspace/p04_submission_archive_20260516_082924/final_structure_cleanup/.venv/bin/python"
fi

run() {
  echo
  echo "+ $*"
  "$@"
}

{
  echo "======================================================================"
  echo "ANVIL P-04 · PCAM PRECISION AGENT · SUBMISSION CHECK"
  echo "======================================================================"
  echo "mode: $MODE"
  echo "folder: $ROOT"
  echo "python: $PY"
  echo "adapter: adapters.theVisioneers:Engine"
  echo "log: $LOG"
  date

  echo
  echo "======================================================================"
  echo "1 / 5 · CLEAN SUBMISSION TREE"
  echo "======================================================================"
  find . -maxdepth 2 -type f \
    ! -path './logs/*' \
    ! -path './.git/*' \
    | sed 's#^./##' | sort

  echo
  echo "======================================================================"
  echo "2 / 5 · CODE QUALITY GATE"
  echo "======================================================================"
  run "$PY" -m py_compile \
    adapter.py adapters/theVisioneers.py adapters/dummy.py adapters/variance.py \
    adapters/class_conditional.py data.py harness.py metrics.py \
    pcam_model.py run.py self_check.py
  run "$PY" -m json.tool reports.json >/dev/null
  echo "code quality: py_compile OK; reports.json valid"

  echo
  echo "======================================================================"
  echo "3 / 5 · OFFICIAL QUICK SELF-CHECK"
  echo "======================================================================"
  run "$PY" self_check.py --adapter adapters.theVisioneers:Engine --quick

  echo
  echo "======================================================================"
  echo "4 / 5 · OFFICIAL 7-SEED REPORT"
  echo "======================================================================"
  if [[ "$MODE" == "--full" ]]; then
    run "$PY" run.py --adapter adapters.theVisioneers:Engine \
      --seeds 7 13 31 97 211 503 1009 --out report.json
  else
    echo "video mode: not rerunning the long 7-seed benchmark."
    echo "showing saved report.json generated by the official command."
  fi

  run "$PY" - <<'PY'
import json
from pathlib import Path
p=Path('report.json')
if not p.exists():
    raise SystemExit('report.json missing; run ./run_submission_checks.sh --full first')
d=json.load(open(p))
print('report.json: valid')
print('seeds:', d['config']['seeds'])
print('mean_delta:', f"{d['aggregated']['mean_delta']:+.4f}")
print('min_delta:', f"{d['aggregated']['min_delta']:+.4f}")
print('mean_spread_reduction:', f"{d['aggregated']['mean_reduction']:.2f}x")
print('retrieval_pts:', d['score']['retrieval_pts'])
print('anisotropy_pts:', d['score']['anisotropy_pts'])
print('total_automated:', d['score']['total_automated'], '/', d['score']['max_automated'])
PY

  echo
  echo "======================================================================"
  echo "5 / 5 · TRANSFER DATASET SUMMARY"
  echo "======================================================================"
  run "$PY" - <<'PY'
import json
r=json.load(open('reports.json'))
for name, item in r['transfer_tests'].items():
    print(f"{name}: baseline={item['baseline']} ({item['baseline_acc']:.4f}) | "
          f"agent={item['agent']} ({item['agent_acc']:.4f}) | delta={item['delta']:+.4f}")
print('\nStress summary current agent:')
s=r['stress_tests']['current_agent']['summary']
print(f"worst_min_delta={s['worst_min_delta']:+.4f}, mean_total_score={s['mean_total_score']:.2f}/90, mean_reduction={s['mean_reduction']:.2f}x")
PY

  echo
  echo "======================================================================"
  echo "DONE"
  echo "======================================================================"
  echo "Saved log: $LOG"
  date
} 2>&1 | tee "$LOG"

# Remove bytecode generated during demo so the submission tree stays clean.
rm -rf __pycache__ adapters/__pycache__
